import { useEffect, useState } from 'react'

import { Link, Outlet, useLocation } from 'react-router-dom'

import {
  Add as AddIcon,
  FitnessCenter,
  CalendarToday,
  Info as InfoIcon,
  InfoOutline as InfoOutlineIcon,
} from '@mui/icons-material'
import {
  Container,
  Typography,
  Box,
  Button,
  Card,
  CardContent,
  CardActions,
  Stack,
  Chip,
  CircularProgress,
  Alert,
  LinearProgress,
  IconButton,
} from '@mui/material'

import { getTrainingExecutionsByPlanId } from '../../api/trainingExecutions'
import { getTrainingPlans } from '../../api/trainingPlans'
import { routes } from '../../routes'
import type { TrainingPlan, TrainingExecution } from '../../types/database'
import {
  calculateTotalSessions,
  calculateEndDate,
  formatDate,
  getWeekDayLabel,
} from '../../utils/schedule'

interface PlanProgress {
  completedUnits: number
  totalExecutions: number
  avgDurationSeconds: number
  avgUnitCount: number
}

function calculatePlanProgress(executions: TrainingExecution[]): PlanProgress {
  if (executions.length === 0) {
    return {
      completedUnits: 0,
      totalExecutions: 0,
      avgDurationSeconds: 0,
      avgUnitCount: 0,
    }
  }

  const completedUnits = executions.reduce((sum, e) => sum + e.unit_count, 0)
  const totalDuration = executions.reduce((sum, e) => sum + e.duration_seconds, 0)

  return {
    completedUnits,
    totalExecutions: executions.length,
    avgDurationSeconds: Math.round(totalDuration / executions.length),
    avgUnitCount: Math.round((completedUnits / executions.length) * 10) / 10,
  }
}

function formatDuration(seconds: number): string {
  if (seconds === 0) return '-'
  const minutes = Math.floor(seconds / 60)
  const secs = seconds % 60
  if (minutes === 0) return `${secs}초`
  return `${minutes}분 ${secs}초`
}

export function PlansPage() {
  const location = useLocation()
  const isListView = location.pathname === '/plans' || location.pathname === '/plans/'

  return (
    <Container maxWidth="md">
      <Box sx={{ my: 4 }}>
        <Box
          sx={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            mb: 3,
          }}
        >
          <Box></Box>
          {/* <Typography variant="h4" component="h1">
            훈련 계획
          </Typography> */}
          {isListView && (
            <Button
              component={Link}
              to={routes.plans.new.$()}
              variant="contained"
              startIcon={<AddIcon />}
            >
              새 계획
            </Button>
          )}
        </Box>
        {isListView ? <PlansList /> : <Outlet />}
      </Box>
    </Container>
  )
}

function PlansList() {
  const [plans, setPlans] = useState<TrainingPlan[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    loadPlans()
  }, [])

  async function loadPlans() {
    try {
      setLoading(true)
      const data = await getTrainingPlans()
      setPlans(data)
    } catch (err) {
      setError('훈련 계획을 불러오는데 실패했습니다.')
      // eslint-disable-next-line no-console
      console.error(err)
    } finally {
      setLoading(false)
    }
  }

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
        <CircularProgress />
      </Box>
    )
  }

  if (error) {
    return <Alert severity="error">{error}</Alert>
  }

  if (plans.length === 0) {
    return <Alert severity="info">아직 훈련 계획이 없습니다. 새 계획을 만들어보세요!</Alert>
  }

  return (
    <Stack spacing={2}>
      {plans.map((plan) => (
        <PlanCard key={plan.id} plan={plan} />
      ))}
    </Stack>
  )
}

function PlanCard({ plan }: { plan: TrainingPlan }) {
  const [progress, setProgress] = useState<PlanProgress | null>(null)
  const [loadingProgress, setLoadingProgress] = useState(true)

  const totalSessions = calculateTotalSessions(plan)
  const endDate = calculateEndDate(plan)

  useEffect(() => {
    async function loadProgress() {
      try {
        const executions = await getTrainingExecutionsByPlanId(plan.id)
        setProgress(calculatePlanProgress(executions))
      } catch {
        // Silently fail
      } finally {
        setLoadingProgress(false)
      }
    }
    loadProgress()
  }, [plan.id])

  const progressPercent = progress
    ? Math.min(100, Math.round((progress.completedUnits / plan.total_amount) * 100))
    : 0

  const [showInfo, setShowInfo] = useState(false)
  return (
    <Card>
      <CardContent>
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: '0.4' }}>
            <CalendarToday sx={{ mr: 1, verticalAlign: 'middle' }} />
            <Typography variant="h6">{plan.name}</Typography>
          </Box>
          <IconButton onClick={() => setShowInfo(!showInfo)}>
            {showInfo ? <InfoIcon /> : <InfoOutlineIcon />}
          </IconButton>
        </Box>
        {showInfo && (
          <>
            <Stack direction="row" flexWrap={'wrap'} spacing={1} sx={{ mb: 1 }}>
              <Chip
                label={`${plan.unit_amount} ${plan.unit_name}/회`}
                size="small"
                variant="outlined"
              />
              <Chip
                label={`총 ${plan.total_amount} ${plan.unit_name}`}
                size="small"
                variant="outlined"
              />
              <Chip
                label={
                  plan.schedule_type === 'daily'
                    ? '매일'
                    : `매주 ${plan.schedule_days?.map(getWeekDayLabel).join(', ')}`
                }
                size="small"
                variant="outlined"
              />
            </Stack>
          </>
        )}

        {/* Progress Section */}
        {loadingProgress ? (
          <LinearProgress sx={{ my: 1 }} />
        ) : (
          progress && (
            <Box>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 0.5 }}>
                <Typography variant="body2" color="text.secondary">
                  진행률
                </Typography>
                <Typography variant="body2" fontWeight="medium">
                  {progress.completedUnits} / {plan.total_amount} {plan.unit_name} (
                  {progressPercent}
                  %)
                </Typography>
              </Box>
              <LinearProgress
                variant="determinate"
                value={progressPercent}
                sx={{ height: 8, borderRadius: 1, mb: 1 }}
              />
              {showInfo && (
                <Stack direction="row" spacing={2} sx={{ mt: 1 }} justifyContent="space-between">
                  <Box>
                    <Typography variant="caption" color="text.secondary">
                      평균 시간: <strong>{formatDuration(progress.avgDurationSeconds)}</strong>•
                      평균 수행량:{' '}
                      <strong>
                        {progress.avgUnitCount} {plan.unit_name}
                      </strong>
                    </Typography>
                  </Box>
                  <Box>
                    <Typography variant="caption" color="text.secondary">
                      수행: <strong>{progress.totalExecutions}회</strong>
                    </Typography>
                  </Box>
                </Stack>
              )}
            </Box>
          )
        )}
        <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
          <Typography variant="body2" color="text.secondary">
            총 {totalSessions}회
          </Typography>
          <Typography variant="body2" color="text.secondary">
            종료 예정: <strong>{formatDate(endDate)}</strong>
          </Typography>
        </Box>
      </CardContent>
      <CardActions sx={{ justifyContent: 'space-between' }}>
        <Button component={Link} to={routes.plans.detail.$path({ id: plan.id }, {})} size="small">
          상세보기
        </Button>
        <Button
          startIcon={<FitnessCenter />}
          component={Link}
          to={routes.executions.new.$({ planId: plan.id })}
          size="small"
          variant="contained"
        >
          훈련시작
        </Button>
      </CardActions>
    </Card>
  )
}
